-- Validate plugin code for obviously dangerous patterns
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size of 64KB"
    end

    -- Patterns that indicate potentially dangerous operations
    local dangerous_patterns = {
        { pattern = "os%.", description = "os module access" },
        { pattern = "io%.", description = "io module access" },
        { pattern = "dofile", description = "dofile usage" },
        { pattern = "loadfile", description = "loadfile usage" },
        { pattern = "require%s*%(?%s*['\"]ffi", description = "FFI access" },
        { pattern = "rawset%s*%(%s*_G", description = "global table modification" },
        { pattern = "rawget%s*%(%s*_G", description = "global table access" },
        { pattern = "getfenv", description = "environment access" },
        { pattern = "setfenv", description = "environment modification" },
        { pattern = "debug%.", description = "debug module access" },
        { pattern = "package%.", description = "package module access" },
        { pattern = "collectgarbage", description = "garbage collector access" },
        { pattern = "newproxy", description = "newproxy usage" },
        { pattern = "coroutine%.create", description = "coroutine creation" },
    }

    for _, dp in ipairs(dangerous_patterns) do
        if ngx.re.find(code, dp.pattern, "jo") then
            return false, "Forbidden pattern detected: " .. dp.description
        end
    end

    return true, nil
end

-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown")
    end

    if REDIS_PASSWORD then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Redis authentication failed: " .. (err or "unknown")
        end
    end

    return red, nil
end

-- Return Redis connection to pool
local function close_redis(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Load plugin code from Redis by plugin name
local function load_plugin_from_redis(plugin_name)
    -- Check shared dict cache first
    local cached_code = plugin_cache and plugin_cache:get("code:" .. plugin_name)
    if cached_code then
        ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
        return cached_code, nil
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    -- Fetch plugin code from Redis
    local code, err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name)
    if not code then
        close_redis(red)
        return nil, "Failed to fetch plugin from Redis: " .. (err or "unknown")
    end

    if code == ngx.null then
        close_redis(red)
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Optionally fetch plugin metadata
    local meta_raw = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    close_redis(red)

    local metadata = nil
    if meta_raw and meta_raw ~= ngx.null then
        local ok, meta = pcall(cjson.decode, meta_raw)
        if ok then
            metadata = meta
            -- Check if plugin is enabled
            if metadata.enabled == false then
                return nil, "Plugin '" .. plugin_name .. "' is disabled"
            end
            -- Check version/checksum if needed
            ngx.log(ngx.INFO, "Plugin '", plugin_name, "' version: ", metadata.version or "unknown")
        end
    end

    -- Cache the code in shared dict
    if plugin_cache then
        plugin_cache:set("code:" .. plugin_name, code, PLUGIN_CACHE_TTL)
    end

    return code, nil
end

-- Compile and execute plugin code in sandbox
local function execute_plugin(code, plugin_name, request_ctx)
    -- Validate code
    local valid, validation_err = validate_plugin_code(code)
    if not valid then
        return nil, "Validation failed for plugin '" .. (plugin_name or "inline") .. "': " .. validation_err
    end

    -- Create sandbox environment
    local sandbox = create_sandbox_env(request_ctx)

    -- Compile the code
    local load_fn = load or loadstring
    local chunk, compile_err = load_fn(code, "=" .. (plugin_name or "inline_plugin"), "t", sandbox)

    if not chunk then
        return nil, "Compilation failed for plugin '" .. (plugin_name or "inline") .. "': " .. (compile_err or "unknown")
    end

    -- If load() doesn't support env argument (Lua 5.1 / LuaJIT), use setfenv
    if setfenv then
        setfenv(chunk, sandbox)
    end

    -- Execute with timeout protection via pcall
    local ok, result = pcall(chunk)
    if not ok then
        return nil, "Execution failed for plugin '" .. (plugin_name or "inline") .. "': " .. tostring(result)
    end

    return result, nil
end

-- Store a plugin in Redis
local function store_plugin(plugin_name, code, metadata)
    local red, err = get_redis_connection()
    if not red then
        return false, err
    end

    local ok, err = red:set(REDIS_PLUGIN_PREFIX .. plugin_name, code)
    if not ok then
        close_redis(red)
        return false, "Failed to store plugin: " .. (err or "unknown")
    end

    if metadata then
        metadata.updated_at = ngx.now()
        local meta_json = cjson.encode(metadata)
        red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta", meta_json)
    end

    close_redis(red)

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
    end

    return true, nil
end

-- List all registered plugins
local function list_plugins()
    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    local keys, err = red:keys(REDIS_PLUGIN_PREFIX .. "*")
    if not keys then
        close_redis(red)
        return nil, "Failed to list plugins: " .. (err or "unknown")
    end

    local plugins = {}
    for _, key in ipairs(keys) do
        -- Filter out metadata keys
        if not ngx.re.find(key, ":meta$", "jo") then
            local name = key:sub(#REDIS_PLUGIN_PREFIX + 1)
            local meta_raw = red:get(key .. ":meta")
            local meta = nil
            if meta_raw and meta_raw ~= ngx.null then
                local ok, m = pcall(cjson.decode, meta_raw)
                if ok then meta = m end
            end
            table.insert(plugins, {
                name = name,
                metadata = meta,
            })
        end
    end

    close_redis(red)
    return plugins, nil
end

-- Delete a plugin from Redis
local function delete_plugin(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return false, err
    end

    red:del(REDIS_PLUGIN_PREFIX .. plugin_name)
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    close_redis(red)

    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
    end

    return true, nil
end

-- Build request context for plugin execution
local function build_request_context()
    ngx.req.read_body()
    local headers = ngx.req.get_headers()
    local args = ngx.req.get_uri_args()
    local body = ngx.req.get_body_data()

    local ctx = {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = args,
        headers = headers,
        body = body,
        remote_addr = ngx.var.remote_addr,
        server_name = ngx.var.server_name,
        request_time = ngx.now(),
        -- Mutable response context
        response = {
            status = nil,
            headers = {},
            body = nil,
        },
        -- Shared data between plugins in same request
        data = {},
    }

    return ctx
end

-- Execute a plugin pipeline (multiple plugins in order)
local function execute_plugin_pipeline(plugin_names, request_ctx)
    local results = {}

    for i, name in ipairs(plugin_names) do
        ngx.log(ngx.INFO, "Executing plugin pipeline step ", i, ": ", name)

        local code, err = load_plugin_from_redis(name)
        if not code then
            ngx.log(ngx.ERR, "Pipeline error at step ", i, " (", name, "): ", err)
            return nil, "Pipeline failed at step " .. i .. " (" .. name .. "): " .. err
        end

        local result, exec_err = execute_plugin(code, name, request_ctx)
        if exec_err then
            ngx.log(ngx.ERR, "Pipeline execution error at step ", i, " (", name, "): ", exec_err)
            return nil, "Pipeline execution failed at step " .. i .. " (" .. name .. "): " .. exec_err
        end

        table.insert(results, {
            plugin = name,
            result = result,
        })

        -- If plugin sets a halt flag, stop the pipeline
        if request_ctx.data and request_ctx.data._halt then
            ngx.log(ngx.INFO, "Pipeline halted by plugin '", name, "'")
            break
        end
    end

    return results, nil
end

