local function handle_request()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri

    -- --------------------------------------------------------
    -- Management API endpoints
    -- --------------------------------------------------------

    -- POST /plugins/register - Register a new plugin
    if uri == "/plugins/register" and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Request body required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local ok, payload = pcall(cjson.decode, body)
        if not ok or not payload.name or not payload.code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Invalid JSON. Required fields: name, code" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        -- Validate code before storing
        local valid, validation_err = validate_plugin_code(payload.code)
        if not valid then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = validation_err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local metadata = {
            version = payload.version or "1.0.0",
            description = payload.description or "",
            author = payload.author or "unknown",
            enabled = payload.enabled ~= false,
            created_at = ngx.now(),
        }

        local stored, store_err = store_plugin(payload.name, payload.code, metadata)
        if not stored then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = store_err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({
            success = true,
            message = "Plugin '" .. payload.name .. "' registered successfully",
            metadata = metadata,
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- GET /plugins - List all plugins
    if uri == "/plugins" and method == "GET" then
        local plugins, err = list_plugins()
        if not plugins then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ plugins = plugins }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- DELETE /plugins/{name} - Delete a plugin
    local delete_match = ngx.re.match(uri, "^/plugins/([\\w\\-]+)$", "jo")
    if delete_match and method == "DELETE" then
        local plugin_name = delete_match[1]
        local ok, err = delete_plugin(plugin_name)
        if not ok then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ success = true, message = "Plugin '" .. plugin_name .. "' deleted" }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- POST /plugins/execute/{name} - Execute a specific plugin by name from Redis
    local exec_match = ngx.re.match(uri, "^/plugins/execute/([\\w\\-]+)$", "jo")
    if exec_match and method == "POST" then
        local plugin_name = exec_match[1]
        local request_ctx = build_request_context()

        local code, load_err = load_plugin_from_redis(plugin_name)
        if not code then
            ngx.status = ngx.HTTP_NOT_FOUND
            ngx.say(cjson.encode({ error = load_err }))
            return ngx.exit(ngx.HTTP_NOT_FOUND)
        end

        local result, exec_err = execute_plugin(code, plugin_name, request_ctx)
        if exec_err then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = exec_err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        -- Apply response from context if plugin set it
        if request_ctx.response.status then
            ngx.status = request_ctx.response.status
        end
        if request_ctx.response.headers then
            for k, v in pairs(request_ctx.response.headers) do
                ngx.header[k] = v
            end
        end
        if request_ctx.response.body then
            ngx.say(request_ctx.response.body)
        else
            ngx.say(cjson.encode({
                success = true,
                plugin = plugin_name,
                result = result,
            }))
        end
        return ngx.exit(ngx.status or ngx.HTTP_OK)
    end

    -- POST /plugins/execute-inline - Execute inline plugin code from request body or header
    if uri == "/plugins/execute-inline" and method == "POST" then
        local request_ctx = build_request_context()
        local plugin_code = nil
        local source = nil

        -- Check for plugin code in header first
        local header_code = ngx.req.get_headers()["X-Plugin-Code"]
        if header_code and #header_code > 0 then
            -- Header code may be base64-encoded
            local decoded = ngx.decode_base64(header_code)
            if decoded then
                plugin_code = decoded
                source = "header-base64"
            else
                plugin_code = header_code
                source = "header-raw"
            end
        end

        -- Fall back to request body
        if not plugin_code then
            ngx.req.read_body()
            local body = ngx.req.get_body_data()
            if body then
                local ok, payload = pcall(cjson.decode, body)
                if ok and payload.code then
                    plugin_code = payload.code
                    source = "body-json"
                else
                    plugin_code = body
                    source = "body-raw"
                end
            end
        end

        if not plugin_code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "No plugin code provided. Use X-Plugin-Code header or request body." }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        ngx.log(ngx.INFO, "Executing inline plugin from source: ", source)

        local result, exec_err = execute_plugin(plugin_code, "inline:" .. source, request_ctx)
        if exec_err then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = exec_err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        if request_ctx.response.status then
            ngx.status = request_ctx.response.status
        end
        if request_ctx.response.headers then
            for k, v in pairs(request_ctx.response.headers) do
                ngx.header[k] = v
            end
        end
        if request_ctx.response.body then
            ngx.say(request_ctx.response.body)
        else
            ngx.say(cjson.encode({
                success = true,
                source = source,
                result = result,
            }))
        end
        return ngx.exit(ngx.status or ngx.HTTP_OK)
    end

    -- POST /plugins/pipeline - Execute multiple plugins in sequence
    if uri == "/plugins/pipeline" and method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Request body required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local ok, payload = pcall(cjson.decode, body)
        if not ok or not payload.plugins or type(payload.plugins) ~= "table" then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Invalid JSON. Required field: plugins (array of plugin names)" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local request_ctx = build_request_context()

        -- Merge any additional context data
        if payload.context and type(payload.context) == "table" then
            for k, v in pairs(payload.context) do
                request_ctx.data[k] = v
            end
        end

        local results, pipeline_err = execute_plugin_pipeline(payload.plugins, request_ctx)
        if pipeline_err then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = pipeline_err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end

        if request_ctx.response.status then
            ngx.status = request_ctx.response.status
        end
        if request_ctx.response.headers then
            for k, v in pairs(request_ctx.response.headers) do
                ngx.header[k] = v
            end
        end
        if request_ctx.response.body then
            ngx.say(request_ctx.response.body)
        else
            ngx.say(cjson.encode({
                success = true,
                pipeline_results = results,
            }))
        end
        return ngx.exit(ngx.status or ngx.HTTP_OK)
    end

    -- POST /plugins/cache/flush - Flush the plugin cache
    if uri == "/plugins/cache/flush" and method == "POST" then
        if plugin_cache then
            plugin_cache:flush_all()
            plugin_cache:flush_expired()
        end
        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ success = true, message = "Plugin cache flushed" }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- --------------------------------------------------------
    -- Gateway mode: execute plugins based on route matching
    -- --------------------------------------------------------

    -- Check for plugin execution via X-Gateway-Plugin header
    local gateway_plugin = ngx.req.get_headers()["X-Gateway-Plugin"]
    if gateway_plugin then
        local request_ctx = build_request_context()

        -- Support comma-separated list of plugins for pipeline
        local plugin_names = {}
        for name in gateway_plugin:gmatch("[^,%s]+") do
            table.insert(plugin_names, name)
        end

        if #plugin_names == 1 then
            local code, load_err = load_plugin_from_redis(plugin_names[1])
            if not code then
                ngx.status = ngx.HTTP_BAD_REQUEST
                ngx.say(cjson.encode({ error = load_err }))
                return ngx.exit(ngx.HTTP_BAD_REQUEST)
            end

            local result, exec_err = execute_plugin(code, plugin_names[1], request_ctx)
            if exec_err then
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = exec_err }))
                return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
            end

            if request_ctx.response.status then
                ngx.status = request_ctx.response.status
            end
            if request_ctx.response.headers then
                for k, v in pairs(request_ctx.response.headers) do
                    ngx.header[k] = v
                end
            end
            if request_ctx.response.body then
                ngx.say(request_ctx.response.body)
            else
                ngx.say(cjson.encode({ success = true, result = result }))
            end
            return ngx.exit(ngx.status or ngx.HTTP_OK)
        elseif #plugin_names > 1 then
            local results, pipeline_err = execute_plugin_pipeline(plugin_names, request_ctx)
            if pipeline_err then
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = pipeline_err }))
                return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
            end

            if request_ctx.response.status then
                ngx.status = request_ctx.response.status
            end
            if request_ctx.response.headers then
                for k, v in pairs(request_ctx.response.headers) do
                    ngx.header[k] = v
                end
            end
            if request_ctx.response.body then
                ngx.say(request_ctx.response.body)
            else
                ngx.say(cjson.encode({ success = true, pipeline_results = results }))
            end
            return ngx.exit(ngx.status or ngx.HTTP_OK)
        end
    end

    -- Default: health check / info endpoint
    if uri == "/" or uri == "/health" then
        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({
            service = "API Gateway Plugin Engine",
            status = "healthy",
            timestamp = ngx.now(),
            endpoints = {
                "POST /plugins/register",
                "GET /plugins",
                "DELETE /plugins/{name}",
                "POST /plugins/execute/{name}",
                "POST /plugins/execute-inline",
                "POST /plugins/pipeline",
                "POST /plugins/cache/flush",
                "Header: X-Gateway-Plugin for transparent plugin execution",
                "Header: X-Plugin-Code for inline code execution",
            },
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- Not found
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say(cjson.encode({ error = "Endpoint not found" }))
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

-- Entry point
ngx.header["Content-Type"] = "application/json"

local ok, err = pcall(handle_request)
if not ok then
    ngx.log(ngx.ERR, "Gateway error: ", err)
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.say(cjson.encode({ error = "Internal gateway error" }))
    return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
end